// 简单烟花点击效果
!function(e){var t=[];e.addEventListener("click",function(n){if(n.target.closest("a,button,input,textarea,select,label"))return;var o=n.clientX,i=n.clientY,c=e.createElement("div");c.style.cssText="position:fixed;left:"+o+"px;top:"+i+"px;width:4px;height:4px;border-radius:50%;pointer-events:none;z-index:9999";var a=["#E52521","#FBD000","#43B047","#049CD8","#FF8C42","#9B59B6"],r=a[Math.floor(Math.random()*a.length)];c.style.background=r,c.style.boxShadow="0 0 8px "+r,e.body.appendChild(c);for(var d=0;d<8;d++){var f=e.createElement("div");f.style.cssText="position:fixed;left:"+o+"px;top:"+i+"px;width:3px;height:3px;border-radius:50%;pointer-events:none;z-index:9999;background:"+r+";box-shadow:0 0 6px "+r,e.body.appendChild(f);var s=Math.cos(d/8*Math.PI*2)*60,u=Math.sin(d/8*Math.PI*2)*60;f.animate([{transform:"translate(0,0) scale(1)",opacity:1},{transform:"translate("+s+"px,"+u+"px) scale(0)",opacity:0}],{duration:600,easing:"cubic-bezier(0.2,0.8,0.4,1)"}),t.push(f)}c.animate([{transform:"scale(1)",opacity:1},{transform:"scale(3)",opacity:0}],{duration:400,easing:"ease-out"}),t.push(c),setTimeout(function(){t.forEach(function(e){e.remove()})},700)})}(document);
